/**
 * Loaders for pre-built graph artifacts.
 * These are JSON files generated by scripts/build-graph.ts
 * and committed to src/data/generated/.
 */
import type { ContentGraph, RelationIndex, TaxonomyIndex, GovernanceIndex } from '../graph/types';

let _graph: ContentGraph | null = null;
let _relations: RelationIndex | null = null;
let _taxonomy: TaxonomyIndex | null = null;
let _governance: GovernanceIndex | null = null;

export async function loadContentGraph(): Promise<ContentGraph> {
  if (_graph) return _graph;
  const mod = await import('../../data/generated/content-graph.json');
  _graph = (mod.default ?? mod) as ContentGraph;
  return _graph;
}

export async function loadRelationIndex(): Promise<RelationIndex> {
  if (_relations) return _relations;
  const mod = await import('../../data/generated/relation-index.json');
  _relations = (mod.default ?? mod) as RelationIndex;
  return _relations;
}

export async function loadTaxonomyIndex(): Promise<TaxonomyIndex> {
  if (_taxonomy) return _taxonomy;
  const mod = await import('../../data/generated/taxonomy-index.json');
  _taxonomy = (mod.default ?? mod) as TaxonomyIndex;
  return _taxonomy;
}

export async function loadGovernanceIndex(): Promise<GovernanceIndex> {
  if (_governance) return _governance;
  const mod = await import('../../data/generated/governance-index.json');
  _governance = (mod.default ?? mod) as GovernanceIndex;
  return _governance;
}
